import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.ResourceAccessException;

import javax.annotation.PostConstruct;
import java.net.InetAddress;
import java.net.MalformedURLException;
import java.net.URL;
import java.net.UnknownHostException;
import java.util.*;
import java.util.regex.Pattern;

@Service
public class WebhookHandlerService {

    private final RestTemplate restTemplate;
    private final Set<String> allowedDomains;
    private final Set<String> blockedIpRanges;
    private final int maxRedirects;
    private final int timeoutMs;

    public WebhookHandlerService(
            RestTemplate restTemplate,
            @Value("${webhook.allowed-domains}") String allowedDomainsStr,
            @Value("${webhook.blocked-ip-ranges}") String blockedIpRangesStr,
            @Value("${webhook.max-redirects:5}") int maxRedirects,
            @Value("${webhook.timeout-ms:10000}") int timeoutMs) {
        this.restTemplate = restTemplate;
        this.maxRedirects = maxRedirects;
        this.timeoutMs = timeoutMs;
        this.allowedDomains = new HashSet<>(Arrays.asList(allowedDomainsStr.split(",")));
        this.blockedIpRanges = new HashSet<>(Arrays.asList(blockedIpRangesStr.split(",")));
    }

    @PostConstruct
    public void validateConfiguration() {
        if (allowedDomains.isEmpty()) {
            throw new IllegalStateException("Allowed domains must be configured");
        }
    }

    public ResponseEntity<String> processWebhook(String webhookUrl, HttpHeaders headers) {
        try {
            URL url = new URL(webhookUrl);
            validateUrl(url);
            validateIpRange(url);

            HttpEntity<String> entity = new HttpEntity<>(headers);
            ResponseEntity<String> response = restTemplate.exchange(
                    webhookUrl,
                    HttpMethod.GET,
                    entity,
                    String.class
            );

            return ResponseEntity.status(response.getStatusCode())
                    .headers(response.getHeaders())
                    .body(response.getBody());

        } catch (MalformedURLException e) {
            return ResponseEntity.badRequest().body("Invalid URL format");
        } catch (HttpClientErrorException e) {
            return ResponseEntity.status(e.getStatusCode()).body(e.getMessage());
        } catch (ResourceAccessException e) {
            return ResponseEntity.status(HttpStatus.REQUEST_TIMEOUT).body("Request timeout or connection error");
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("Error processing webhook");
        }
    }

    private void validateUrl(URL url) throws MalformedURLException {
        if (!allowedDomains.contains(url.getHost())) {
            throw new MalformedURLException("Domain not in allowlist: " + url.getHost());
        }
    }

    private void validateIpRange(URL url) throws UnknownHostException {
        InetAddress address = InetAddress.getByName(url.getHost());
        String hostAddress = address.getHostAddress();

        if (isPrivateOrInternalIp(hostAddress)) {
            throw new UnknownHostException("Access to private/internal IP ranges is blocked: " + hostAddress);
        }

        for (String blockedRange : blockedIpRanges) {
            if (isIpInSubnet(hostAddress, blockedRange)) {
                throw new UnknownHostException("Access to blocked IP range: " + blockedRange);
            }
        }
    }

    private boolean isPrivateOrInternalIp(String ipAddress) {
        if (ipAddress.startsWith("127.") || ipAddress.startsWith("10.") || 
            ipAddress.startsWith("172.") || ipAddress.startsWith("192.168.")) {
            return true;
        }
        return false;
    }

    private boolean isIpInSubnet(String ipAddress, String subnet) {
        try {
            String[] parts = subnet.split("/");
            String subnetIp = parts[0];
            int prefixLength = Integer.parseInt(parts[1]);

            long subnetLong = ipToLong(subnetIp);
            long ipLong = ipToLong(ipAddress);
            long mask = (-1L) << (32 - prefixLength);
            return (ipLong & mask) == (subnetLong & mask);
        } catch (Exception e) {
            return false;
        }
    }

    private long ipToLong(String ipAddress) {
        String[] ipParts = ipAddress.split("\\.");
        long result = 0;
        for (int i = 0; i < 4; i++) {
            int octet = Integer.parseInt(ipParts[i]);
            result |= (long) octet << (8 * (3 - i));
        }
        return result;
    }
}